public class Codec {
    private static final String BASE_URL = "http://tinyurl.com/";
    private static final String CHARACTERS = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
    private final java.util.HashMap<String, String> urlMap = new java.util.HashMap<>();

    // Encodes a URL to a shortened URL.
    public String encode(String longUrl) {
        StringBuilder shortUrl = new StringBuilder(BASE_URL);
        String key = generateKey();
        while (urlMap.containsKey(key)) {
            key = generateKey();
        }
        urlMap.put(key, longUrl);
        shortUrl.append(key);
        return shortUrl.toString();
    }

    // Decodes a shortened URL to its original URL.
    public String decode(String shortUrl) {
        return urlMap.get(shortUrl.substring(BASE_URL.length()));
    }

    private String generateKey() {
        StringBuilder key = new StringBuilder();
        for (int i = 0; i < 6; i++) {
            key.append(CHARACTERS.charAt((int) (Math.random() * CHARACTERS.length())));
        }
        return key.toString();
    }
}
